changeSet.sql:
ALTER TABLE organizations ADD COLUMN is_technology_vendor boolean DEFAULT false;
ALTER TABLE organizations ADD COLUMN is_system_vendor boolean DEFAULT true;
ALTER TABLE organizations ADD COLUMN is_service_vendor boolean DEFAULT false;

UPDATE organizations SET is_technology_vendor=false WHERE org_type='Vendor';
UPDATE organizations SET is_system_vendor=true WHERE org_type='Vendor';
UPDATE organizations SET is_service_vendor=false WHERE org_type='Vendor';

